import base64
import json

MD_B64 = ""
TOML_B64 = ""

def canonize():
    report = {
        "SubstrateID": "1103_btfs_depin_storage",
        "Name": "BTFS-DEPIN-STORAGE",
        "Status": "CANONIZED_PROVISIONAL",
        "Seal": "BTFS-CATHEDRAL-1103-v1.0.0-2026-06-12",
        "Files": {
            "cathedral_btfs_integration_1103.md": base64.b64decode(MD_B64).decode("utf-8"),
            "substrate.toml": base64.b64decode(TOML_B64).decode("utf-8")
        }
    }

    return json.dumps(report, indent=2)

if __name__ == "__main__":
    print(canonize())
